 20	// providerModelsFetcher is the live discovery fetcher used by the cache. It
 21	// is a package var so tests can replace it without standing up a real
 22	// fizeau service. Production code uses fetchProviderModelsLive.
 23	var providerModelsFetcher = fetchProviderModelsLive
 24	
 25	type providerModelsCacheEntry struct {
 26		result    *ProviderModelsResult
 27		fetchedAt time.Time
 28	}
 29	
 30	var providerModelsCache = struct {
 31		sync.Mutex
 32		entries  map[string]providerModelsCacheEntry
 33		inFlight map[string]chan struct{}
 34	}{
 35		entries:  make(map[string]providerModelsCacheEntry),
 36		inFlight: make(map[string]chan struct{}),
 37	}
