 39	func providerModelsCacheKey(workDir, name string, kind ProviderKind) string {
 40		return workDir + "\x00" + strings.ToLower(strings.TrimSpace(name)) + "\x00" + string(kind)
 41	}
 42	
 43	// ProviderModels is the resolver for the providerModels query.
 44	// Returns a cached snapshot when one is fresh (within TTL); otherwise issues
 45	// a single coalesced live fetch (in-flight guard prevents duplicate concurrent
 46	// discovery calls for the same key).
 47	func (r *queryResolver) ProviderModels(ctx context.Context, name string, kind ProviderKind) (*ProviderModelsResult, error) {
 48		name = strings.TrimSpace(name)
 49		if name == "" {
 50			return nil, fmt.Errorf("name required")
 51		}
 52		if !kind.IsValid() {
 53			return nil, fmt.Errorf("invalid kind: %s", kind)
 54		}
 55	
 56		key := providerModelsCacheKey(r.workingDir(ctx), name, kind)
 57	
 58		if cached, ok := lookupProviderModelsCache(key); ok {
 59			// Serve cached copy with fromCache=true; do NOT alter fetchedAt.
 60			out := cloneProviderModelsResult(cached.result)
 61			out.FromCache = true
 62			return out, nil
 63		}
 64	
 65		res, err := loadProviderModels(ctx, r.workingDir(ctx), name, kind, key)
 66		if err != nil {
 67			return nil, err
 68		}
 69		out := cloneProviderModelsResult(res)
 70		out.FromCache = false
 71		return out, nil
 72	}
 73	
 74	// RefreshProviderModels is the resolver for the refreshProviderModels mutation.
 75	// Always performs a live discovery, ignoring TTL, but still routes through the
 76	// in-flight guard so concurrent refreshes for the same key are coalesced.
 77	// Auth-gating is provided by the requireTrusted wrapper on the /graphql HTTP
 78	// route (see cli/internal/server/server.go); this resolver runs only for
 79	// trusted callers.
 80	func (r *mutationResolver) RefreshProviderModels(ctx context.Context, name string, kind ProviderKind) (*ProviderModelsResult, error) {
 81		name = strings.TrimSpace(name)
 82		if name == "" {
 83			return nil, fmt.Errorf("name required")
 84		}
 85		if !kind.IsValid() {
 86			return nil, fmt.Errorf("invalid kind: %s", kind)
 87		}
 88	
 89		key := providerModelsCacheKey(r.workingDir(ctx), name, kind)
 90		res, err := refreshProviderModels(ctx, r.workingDir(ctx), name, kind, key)
 91		if err != nil {
 92			return nil, err
 93		}
 94		out := cloneProviderModelsResult(res)
 95		out.FromCache = false
 96		return out, nil
 97	}
 98	
 99	// lookupProviderModelsCache returns the cached entry when it is still fresh.
100	func lookupProviderModelsCache(key string) (providerModelsCacheEntry, bool) {
101		providerModelsCache.Lock()
102		defer providerModelsCache.Unlock()
103		entry, ok := providerModelsCache.entries[key]
104		if !ok || entry.result == nil {
105			return providerModelsCacheEntry{}, false
106		}
107		if time.Since(entry.fetchedAt) > providerModelsCacheTTL {
108			return providerModelsCacheEntry{}, false
109		}
110		return entry, true
111	}
112	
113	// loadProviderModels returns a fresh result, performing a live discovery only
114	// when no other goroutine is already doing so. When an in-flight fetch exists
115	// for this key, the caller waits on its completion and then reads the cache.
116	func loadProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
117		return doProviderModelsFetch(ctx, workDir, name, kind, key, false)
118	}
119	
120	// refreshProviderModels forces a live discovery (no TTL check), still
121	// coalescing concurrent calls for the same key.
122	func refreshProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
123		return doProviderModelsFetch(ctx, workDir, name, kind, key, true)
124	}
125	
126	func doProviderModelsFetch(ctx context.Context, workDir, name string, kind ProviderKind, key string, force bool) (*ProviderModelsResult, error) {
127		for {
128			providerModelsCache.Lock()
129			// If a fetch is in flight for this key, wait for it and re-evaluate.
130			if ch, ok := providerModelsCache.inFlight[key]; ok {
131				providerModelsCache.Unlock()
132				select {
133				case <-ch:
134					if !force {
135						if entry, ok := lookupProviderModelsCache(key); ok {
136							return entry.result, nil
137						}
138					}
139					// Fall through to retry — we either need a fresh fetch or the
140					// previous attempt failed.
141					continue
142				case <-ctx.Done():
143					return nil, ctx.Err()
144				}
145			}
146			// We own the in-flight slot.
147			ch := make(chan struct{})
148			providerModelsCache.inFlight[key] = ch
149			providerModelsCache.Unlock()
150	
151			result, err := providerModelsFetcher(ctx, workDir, name, kind)
152	
153			providerModelsCache.Lock()
154			delete(providerModelsCache.inFlight, key)
155			if err == nil && result != nil {
156				providerModelsCache.entries[key] = providerModelsCacheEntry{
157					result:    result,
158					fetchedAt: time.Now().UTC(),
159				}
160			}
161			providerModelsCache.Unlock()
162			close(ch)
163	
164			if err != nil {
165				return nil, err
166			}
167			return result, nil
168		}
169	}
