119	// ProviderTrend is the resolver for the providerTrend field.
120	// It aggregates the sessions index into time buckets for one provider/harness
121	// and computes a projected-run-out-in-hours callout from the last-24h slope.
122	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
123		name = strings.TrimSpace(name)
124		if name == "" {
125			return nil, fmt.Errorf("name required")
126		}
127		if windowDays != 7 && windowDays != 30 {
128			return nil, fmt.Errorf("windowDays must be 7 or 30")
129		}
130		now := time.Now().UTC()
131		entries := r.sessionIndexEntries(ctx)
132	
133		kind, detected := detectProviderOrHarness(ctx, r, name)
134		bucketKind := agent.MatchProvider
135		if kind == ProviderKindHarness {
136			bucketKind = agent.MatchHarness
137		}
138	
139		bucketSize := time.Hour
140		if windowDays > 7 {
141			bucketSize = 4 * time.Hour
142		}
143		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
144		series := make([]*ProviderTrendPoint, 0, len(buckets))
145		for _, b := range buckets {
146			series = append(series, &ProviderTrendPoint{
147				BucketStart: b.Start.UTC().Format(time.RFC3339),
148				Tokens:      b.Tokens,
149				Requests:    b.Requests,
150			})
151		}
152	
153		trend := &ProviderTrend{
154			Name:       name,
155			Kind:       kind,
156			WindowDays: windowDays,
157			Series:     series,
158		}
159	
160		if detected != nil {
161			if ceiling := detected.ceilingTokens; ceiling > 0 {
162				c := ceiling
163				trend.CeilingTokens = &c
164				remaining := detected.remaining
165				if remaining < 0 {
166					remaining = ceiling - sumTailTokens(buckets, 24)
167				}
168				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
169					trend.ProjectedRunOutHours = &p
170				}
171			}
172		}
173	
174		return trend, nil
175	}
