 11	func TestSanitizeBaseURL(t *testing.T) {
 12		cases := []struct {
 13			in   string
 14			want string
 15		}{
 16			{"https://api.example.com/v1", "https://api.example.com/v1"},
 17			{"https://user:pass@api.example.com/v1?key=secret#frag", "https://api.example.com/v1"},
 18			{"http://localhost:8080", "http://localhost:8080"},
 19			{"  https://host.tld  ", "https://host.tld"},
 20			{"", ""},
 21			{"not a url", ""},
 22			{"file:///etc/passwd", ""}, // no host
 23		}
 24		for _, tc := range cases {
 25			if got := sanitizeBaseURL(tc.in); got != tc.want {
 26				t.Errorf("sanitizeBaseURL(%q) = %q, want %q", tc.in, got, tc.want)
 27			}
 28		}
 29	}
