 31	// TestProviderModelsCacheServesFromCacheWithinTTL verifies that a second
 32	// query within the TTL does not invoke the live fetcher and surfaces
 33	// fromCache=true without mutating the cached fetchedAt timestamp.
 34	func TestProviderModelsCacheServesFromCacheWithinTTL(t *testing.T) {
 35		providerModelsCache.Lock()
 36		providerModelsCache.entries = make(map[string]providerModelsCacheEntry)
 37		providerModelsCache.inFlight = make(map[string]chan struct{})
 38		providerModelsCache.Unlock()
 39		t.Cleanup(func() {
 40			providerModelsCache.Lock()
 41			providerModelsCache.entries = make(map[string]providerModelsCacheEntry)
 42			providerModelsCache.inFlight = make(map[string]chan struct{})
 43			providerModelsCache.Unlock()
 44		})
 45	
 46		var calls int32
 47		prev := providerModelsFetcher
 48		providerModelsFetcher = func(ctx context.Context, workDir, name string, kind ProviderKind) (*ProviderModelsResult, error) {
 49			atomic.AddInt32(&calls, 1)
 50			return &ProviderModelsResult{
 51				Name:      name,
 52				Kind:      kind,
 53				BaseURL:   "https://api.example.com",
 54				FetchedAt: time.Now().UTC().Format(time.RFC3339),
 55			}, nil
 56		}
 57		t.Cleanup(func() { providerModelsFetcher = prev })
 58	
 59		r := &queryResolver{Resolver: &Resolver{WorkingDir: "/tmp/wd"}}
 60		ctx := context.Background()
 61	
 62		first, err := r.ProviderModels(ctx, "openai", ProviderKindEndpoint)
 63		if err != nil {
 64			t.Fatalf("first call: %v", err)
